const proyecto = $input.item.json.proyecto || "PVV";
const tipo = ($input.item.json.tipo_media || "amenidades").toLowerCase().trim();
const canal = ($input.item.json.canal || "whatsapp").toLowerCase().trim();

// Mapeo inicial de recursos multimedia por proyecto.
// Debes cambiar estos URLs por los oficiales de cada proyecto.
const database = {
  "PVV": {
    "amenidades": "https://res.cloudinary.com/dif0pqsok/image/upload/v1763745364/amenidades_dble4k.png",
    "renders": "https://res.cloudinary.com/dif0pqsok/image/upload/v1763745364/amenidades_dble4k.png", // Reemplazar
    "planos": "https://res.cloudinary.com/dif0pqsok/image/upload/v1763745364/amenidades_dble4k.png", // Reemplazar
    "brochure": "https://res.cloudinary.com/dif0pqsok/image/upload/v1763745364/amenidades_dble4k.png" // Reemplazar
  },
  "PMAR": {
    "amenidades": "https://link-de-prueba.com/amenidades.png",
    "renders": "https://link-de-prueba.com/renders.png",
    "planos": "https://link-de-prueba.com/planos.png",
    "brochure": "https://link-de-prueba.com/brochure.png"
  },
  "PPO": {
    "amenidades": "https://link-de-prueba.com/amenidades.png",
    "renders": "https://link-de-prueba.com/renders.png",
    "planos": "https://link-de-prueba.com/planos.png",
    "brochure": "https://link-de-prueba.com/brochure.png"
  }
};

const projectData = database[proyecto] || database["PVV"];
let url = projectData[tipo];

// Fallback: si piden algo que no está en la lista, mandamos amenidades por defecto
if (!url) {
  url = projectData["amenidades"];
}

// Lógica extraída del flujo antiguo: Si es whatsapp y la cuenta manda urls en vez de imagen pura, 
// mantenemos esa estructura (envíar como texto en whatsapp, o como imagen en IG/FB).
const objectType = canal === 'whatsapp' ? 'text' : 'image';
const keyName = canal === 'whatsapp' ? 'text' : 'url';

return [{
  json: {
    manychat_id: $input.item.json.manychat_id,
    canal: canal,
    url: url,
    objectType: objectType,
    keyName: keyName
  }
}];
